  ('elementary-8b44517b-moex-00951', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '行政訴訟若以公法人之機關為被告，原則上應由那一個行政法院管轄？', '["由被告機關所在地之行政法院管轄", "由原告戶籍所在地之行政法院管轄", "由原告住所地之行政法院管轄", "一律以中央政府所在地之行政法院管轄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00952', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲死亡後留下數筆存款及土地，其子女乙、丙、丁、戊為繼承人。甲遺囑中表示四大房子孫要團結，故 不得分割遺產。下列敘述何者正確？', '["乙、丙、丁、戊不能分割，要傳給後代變成祭祀公業", "乙為繼承人，得隨時請求分割遺產，丙、丁、戊不得拒絕", "乙、丙、丁、戊不能分割，但繼承開始10年後，得請求分割遺產", "乙、丙、丁、戊於甲死後，因遺囑禁止分割，依民法規定，遺產於20年內均不得分割"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00953', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於民事訴訟代理人之敘述，何者正確？', '["簡易事件第二審之訴訟代理人，應委任具有教育部認證之法律相關科系獲碩士學位以上者，擔任訴訟 代理人。該訴訟代理人之酬金，由國庫墊之", "訴訟代理人就其受委任之事件有為一切訴訟行為之權。但捨棄、認諾、撤回、和解、提起反訴、上訴 或再審之訴及選任代理人，非受特別委任不得為之", "訴訟代理人有二人以上者，應共同代理當事人，不得單獨為之", "訴訟代理人為當事人聲請訴之追加、變更或提起反訴時，應先以書面聲請法院得審判長同意後，並為 當事人先墊付訴訟費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
